(window["webpackJsonp"]=window["webpackJsonp"]||[]).push([["learn33"],{1032:function(r,n){r.exports="### 环境搭建\r\n\r\nIDE pycharm安装地址\r\n```\r\nhttps://www.jetbrains.com/zh/pycharm/specials/pycharm/pycharm.html\r\n```\r\n\r\nmysql重置密码\r\n\r\n```s\r\nmysql -u root -p\r\nshow databases\r\nuse mysql\r\nshow tables;\r\ndesc user;\r\nupdate user set authentication_string=PASSWORD('root') where user='root';\r\n```\r\n\r\nsequel pro安装地址\r\n```\r\nhttps://sequelpro.com/download\r\n```\r\n\r\n### virtualenv介绍\r\n\r\nvirtualenv优点\r\n```\r\n使不同应用开发环境独立\r\n环境升级不影响其他应用，也不会影响全局的python环境\r\n它可以防止系统中出现包管理混乱和版本的冲突\r\n```\r\n安装virtualenv\r\n```\r\npip install -i https://pypi.douban.com/simple virtualenv\r\npip install -i https://pypi.douban.com/simple virtualenvwrapper\r\n```\r\nMac上提示安装virtualenvwrapper成功，但mkvirtualenv testenv时提示无法找到命令\r\n```\r\n1.你先运行 sudo find / -name virtualenvwrapper.sh 找到shell文件路径 \r\n2.然后vim ~/.bashrc 然后 在文件中添加 source 你找到的路径/virtualenvwrapper.sh \r\n3.然后 source ~/.bashrc\r\n```\r\n\r\n```s\r\n# 创建虚拟环境 testvir2\r\nmkvirtualenv testvir2\r\n# 退出虚拟环境\r\ndeactivate\r\n# 查看虚拟环境 \r\nworkon\r\n# 进入虚拟环境\r\nworkon testvir2\r\n# 列出pip下的安装包\r\npip list\r\n# 安装requests包\r\npip install requests\r\n# 卸载requests包\r\npip uninstall requests\r\n```\r\n\r\n### pycharm的使用\r\n```s\r\n1. New Project\r\n2. 选择虚拟环境，/Users/zhangyu/.virualenvs/testvir2/bin/python\r\n3. 查看虚拟环境的安装包, File =>首选项 =>  Project Interpreter\r\n4. 设置快捷键，File =>首选项 => Keymap\r\n5. 进行url配置，Run => Edit \r\n```\r\n用python3 manage.py runserver 0.0.0.0:8000命令运行django程序后，通过浏览器访问服务器网址的8000端口，出现访问错误，报错为 \r\nInvalid HTTP_HOST header: ‘xxx.xx.xxx.xxx:8000’. You may need to add ‘xxx.xx’ to ALLOWED_HOSTS\r\n```s\r\n解决办法： \r\n修改创建项目时生成的setting.py文件\r\n将ALLOWED_HOSTS = []改为ALLOWED_HOSTS = ['*']\r\n```\r\nSequel Pro 使用\r\n```s\r\nhttps://blog.csdn.net/huacha__/article/details/81662142\r\nhttps://www.jianshu.com/p/c5276a8dd397\r\n```\r\n\r\n[mac开发环境搭建](http://www.imooc.com/article/25365)\r\n\r\n### 目录结构\r\n生成app\r\n```s\r\n1.Tools=> Run manage.py Task\r\n2.startapp message\r\n3.新建static文件夹，存放js、cs、图片文件\r\n4.新建log文件夹，存放日志文件\r\n5.新建media文件夹，存放用户上传文件\r\n6.新建apps文件夹，存放各种APP\r\n7.把刚才新建的message文件夹拖到apps里边去\r\n```\r\n目录说明\r\n```\r\n自动生成：主目录文件中setting全局配置，url配置入口，templates放html文件，manage启动dj主要文件\r\ntools-run manage.py task，startapp message新建app\r\nstatic存放js、cs、图片文件\r\nlog存放日志文件\r\nmedia存放用户上传文件\r\napps存放各种APP\r\nmanage.py引入APP from apps.message import views\r\nmark message后，可以直接from .message import views，不提示错误，但是还需要在settings配置根目录搜索路径\r\n```\r\n在setting中设置 apps的搜索路径\r\n```py\r\nimport sys #引入sys包\r\n\r\n# Build paths inside the project like this: os.path.join(BASE_DIR, ...)\r\nBASE_DIR = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))\r\nsys.path.insert(0, os.path.join(BASE_DIR, 'apps'))\r\n```\r\n\r\n### 配置表单页面\r\n\r\n1. 配置数据库，连接mysql\r\n```python\r\nDATABASES = {\r\n    'default': {\r\n        'ENGINE': 'django.db.backends.mysql',\r\n        'NAME': 'testdjango',\r\n        'USER':'root',\r\n        'PASSWORD':'as110120',\r\n        'HOST':'127.0.0.1'\r\n    }\r\n}\r\n```\r\n2.生成django自带的数据表\r\n```s\r\n1.Tools=> Run manage.py Task\r\n(此时会报错：Error loading MySQLdb module: No module named MySQLdb.)\r\n2.安装MySQLdb，进入虚拟环境 \r\n  workon djangostart \r\n  pip install mysqlclient\r\n3.生成数据表\r\n  makemigrations\r\n  migrate\r\n\r\n  makemigrations会在当前目录下生成一个migrations文件夹，该文件夹的内容就是数据库要执行的内容 \r\n  python manage.py makemigrations \r\n  migrate就是执行之前生成的migrations文件，这一步才是操作数据库的一步 \r\n  python manage.py migrate \r\n\r\n  Django每次更新模型都需要执行以上两步，需要注意的是Django模型增加内容需要设定变量的初始值，否则会在第一步出现问题\r\n```\r\n\r\nurls.py 下添加路由\r\n```py\r\nfrom django.conf.urls import url\r\nfrom django.contrib import admin\r\n\r\nfrom message.views import getform\r\n\r\nurlpatterns = [\r\n    url(r'^admin/', admin.site.urls),\r\n    url(r'^form/$',getform)\r\n]\r\n```\r\napp的views.py 下边创建views\r\n```py\r\n# -*- coding: utf-8 -*-\r\nfrom __future__ import unicode_literals\r\n\r\nfrom django.shortcuts import render\r\n\r\n# Create your views here.\r\ndef getform(request):\r\n    return render(request,'message_form.html')\r\n```\r\n在setting.py下边添加templates的路径\r\n```py\r\n\r\nTEMPLATES = [\r\n    {\r\n        'BACKEND': 'django.template.backends.django.DjangoTemplates',\r\n        'DIRS': [os.path.join(BASE_DIR, 'templates')]\r\n        ,\r\n        'APP_DIRS': True,\r\n        'OPTIONS': {\r\n            'context_processors': [\r\n                'django.template.context_processors.debug',\r\n                'django.template.context_processors.request',\r\n                'django.contrib.auth.context_processors.auth',\r\n                'django.contrib.messages.context_processors.messages',\r\n            ],\r\n        },\r\n    },\r\n]\r\n```\r\n在setting.py下边添加static的路径\r\n```py\r\nSTATIC_URL = '/static/'\r\nSTATICFILES_DIRS = [\r\n    os.path.join(BASE_DIR,'static')\r\n]\r\n```\r\n![](https://raw.githubusercontent.com/sunny586/sunny586.github.io/master/images/py/xmpzlc.jpg)\r\n"},ece6:function(r,n,e){"use strict";e.r(n);var t=function(){var r=this,n=r.$createElement,t=r._self._c||n;return t("markdown",{attrs:{source:e("1032")}})},s=[],a=e("2877"),o={},p=Object(a["a"])(o,t,s,!1,null,null,null);p.options.__file="python.vue";n["default"]=p.exports}}]);